import React, { useState, useEffect } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("notes");

  const [patient, setPatient] = useState({
    name: "",
    age: "",
    gender: "",
    mrn: "",
    visitId: "",
    department: "",
    photo: null
  });

  const [vitals, setVitals] = useState({
    hr: "",
    sys: "",
    dia: "",
    rr: "",
    spo2: "",
    temp: ""
  });

  const [redFlags, setRedFlags] = useState({
    chestPain: false,
    hypoxia: false,
    trauma: false,
    seizure: false
  });

  const [aiLevel, setAiLevel] = useState("LEVEL 5 – NON-URGENT");
  const [triage, setTriage] = useState("LEVEL 5");
  const [nurse, setNurse] = useState("");

  // ================= AI TRIAGE ENGINE =================
  useEffect(() => {
    const { hr, sys, dia, rr, spo2, temp } = vitals;

    let level = "LEVEL 5 – NON-URGENT";

    // ===== LEVEL 1 : CRITICAL =====
    if (
      Number(spo2) < 90 ||
      Number(hr) > 130 ||
      Number(sys) < 90 ||
      redFlags.seizure ||
      redFlags.trauma
    ) {
      level = "LEVEL 1 – CRITICAL";
    }

    // ===== LEVEL 2 : EMERGENT =====
    else if (
      redFlags.chestPain ||
      redFlags.hypoxia ||
      Number(temp) >= 39 ||
      Number(rr) > 25
    ) {
      level = "LEVEL 2 – EMERGENT";
    }

    // ===== LEVEL 3 : URGENT =====
    else if (
      Number(hr) > 100 ||
      Number(rr) > 20 ||
      Number(temp) > 38
    ) {
      level = "LEVEL 3 – URGENT";
    }

    // ===== LEVEL 4 : SEMI URGENT =====
    else if (
      hr ||
      sys ||
      dia ||
      rr ||
      spo2 ||
      temp
    ) {
      level = "LEVEL 4 – SEMI-URGENT";
    }

    setAiLevel(level);
    setTriage(level.split("–")[0].trim());

  }, [vitals, redFlags]);

  return (
    <div className="emr-wrapper">

      {/* ================= HEADER ================= */}
      <div className="emr-header">
        <div className="profile">
          <label>
            <input
              type="file"
              hidden
              accept="image/*"
              onChange={(e) =>
                setPatient({
                  ...patient,
                  photo: URL.createObjectURL(e.target.files[0])
                })
              }
            />
            <img
              src={patient.photo || "https://via.placeholder.com/90"}
              alt="patient"
            />
          </label>

          <div>
            <input placeholder="Patient Name" />
            <div className="sub">
              <input placeholder="Age" />
              <input placeholder="Gender" />
            </div>
          </div>
        </div>
      </div>

      {/* ================= VISIT INFO ================= */}
      <div className="visit-strip">
        <input placeholder="MRN" />
        <input placeholder="Visit ID" />
        <input placeholder="Department" />
      </div>

      {/* ================= TABS ================= */}
      <div className="tabs">
        <button
          className={tab === "notes" ? "active" : ""}
          onClick={() => setTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "notes" && (
        <div className="card">
          <label>Chief Complaint</label>
          <input />

          <label>History of Present Illness</label>
          <textarea />

          <label>Assessment</label>
          <textarea />

          <label>Plan</label>
          <textarea />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="card">

          <h3>Vital Signs</h3>

          <div className="grid">
            <input placeholder="Heart Rate 60–100 bpm"
              onChange={e => setVitals({ ...vitals, hr: e.target.value })} />

            <input placeholder="BP Systolic 90–120 mmHg"
              onChange={e => setVitals({ ...vitals, sys: e.target.value })} />

            <input placeholder="BP Diastolic 60–80 mmHg"
              onChange={e => setVitals({ ...vitals, dia: e.target.value })} />

            <input placeholder="Respiratory Rate 12–20 /min"
              onChange={e => setVitals({ ...vitals, rr: e.target.value })} />

            <input placeholder="SpO₂ 95–100 %"
              onChange={e => setVitals({ ...vitals, spo2: e.target.value })} />

            <input placeholder="Temperature 36.5–37.5 °C"
              onChange={e => setVitals({ ...vitals, temp: e.target.value })} />
          </div>

          {/* ===== RED FLAGS ===== */}
          <h3>Red Flags Detected</h3>
          <div className="checks">
            {Object.keys(redFlags).map((key) => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={redFlags[key]}
                  onChange={() =>
                    setRedFlags({ ...redFlags, [key]: !redFlags[key] })
                  }
                />
                {key}
              </label>
            ))}
          </div>

          {/* ===== AI RESULT ===== */}
          <div className={`ai-box ${triage.toLowerCase()}`}>
            <h3>AI Suggested Level</h3>
            <strong>{aiLevel}</strong>
          </div>

          {/* ===== TRIAGE BUTTONS ===== */}
          <h3>Triage Level</h3>
          <div className="triage">
            {[
              "LEVEL 1",
              "LEVEL 2",
              "LEVEL 3",
              "LEVEL 4",
              "LEVEL 5"
            ].map(level => (
              <button
                key={level}
                className={triage === level ? "active" : ""}
                onClick={() => setTriage(level)}
              >
                {level}
              </button>
            ))}
          </div>

          {/* ===== ISOLATION ===== */}
          <h3>Isolation</h3>
          <div className="checks">
            <label><input type="checkbox" /> Droplet</label>
            <label><input type="checkbox" /> Contact</label>
            <label><input type="checkbox" /> None</label>
          </div>

          {/* ===== NURSE ===== */}
          <label>Nurse Name</label>
          <input
            value={nurse}
            onChange={(e) => setNurse(e.target.value)}
          />

        </div>
      )}

      {/* ================= FOOTER ================= */}
      <div className="footer-btns">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>

    </div>
  );
}
